    /// Execute the current step
    pub async fn execute_step(&self, instance: &mut TemporaryPermissionGrantFlowInstance) -> Result<(), FlowError> {
        let current_step = match instance.current_step {
            Some(step) => step,
            None => return Err(FlowError::NoCurrentStep),
        };

        let next_step = match current_step {
            TemporaryPermissionGrantFlowStep::ValidateDuration => {
                self.0.handler.handle_validate_duration(instance).await?
            }
            TemporaryPermissionGrantFlowStep::CheckDuration => {
                let next = self.0.handler.evaluate_check_duration(instance).await?;
                Some(next)
            }
            TemporaryPermissionGrantFlowStep::LogValidationError => {
                self.0.handler.handle_log_validation_error(instance).await?
            }
            TemporaryPermissionGrantFlowStep::CheckDuplicates => {
                self.0.handler.handle_check_duplicates(instance).await?
            }
            TemporaryPermissionGrantFlowStep::HandleDuplicate => {
                let next = self.0.handler.evaluate_handle_duplicate(instance).await?;
                Some(next)
            }
            TemporaryPermissionGrantFlowStep::LogDuplicate => {
                self.0.handler.handle_log_duplicate(instance).await?
            }
            TemporaryPermissionGrantFlowStep::ActivatePermission => {
                self.0.handler.handle_activate_permission(instance).await?
            }
            TemporaryPermissionGrantFlowStep::LogActivationError => {
                self.0.handler.handle_log_activation_error(instance).await?
            }
            TemporaryPermissionGrantFlowStep::LogActivation => {
                self.0.handler.handle_log_activation(instance).await?
            }
            TemporaryPermissionGrantFlowStep::NotifyUser => {
                self.0.handler.handle_notify_user(instance).await?
            }
            TemporaryPermissionGrantFlowStep::InvalidateCache => {
                self.0.handler.handle_invalidate_cache(instance).await?
            }
            TemporaryPermissionGrantFlowStep::AwaitExpiry => {
                self.0.handler.handle_await_expiry(instance).await?
            }
            TemporaryPermissionGrantFlowStep::LogExpiry => {
                self.0.handler.handle_log_expiry(instance).await?
            }
            TemporaryPermissionGrantFlowStep::CheckAndExpire => {
                self.0.handler.handle_check_and_expire(instance).await?
            }
            TemporaryPermissionGrantFlowStep::HandleExpiryCheck => {
                let next = self.0.handler.evaluate_handle_expiry_check(instance).await?;
                Some(next)
            }
            TemporaryPermissionGrantFlowStep::AutoExpire => {
                self.0.handler.handle_auto_expire(instance).await?
            }
            TemporaryPermissionGrantFlowStep::LogAutoExpiry => {
                self.0.handler.handle_log_auto_expiry(instance).await?
            }
            TemporaryPermissionGrantFlowStep::LogAlreadyRevoked => {
                self.0.handler.handle_log_already_revoked(instance).await?
            }
            TemporaryPermissionGrantFlowStep::InvalidateCacheAfterExpiry => {
                self.0.handler.handle_invalidate_cache_after_expiry(instance).await?
            }
            TemporaryPermissionGrantFlowStep::NotifyExpiry => {
                self.0.handler.handle_notify_expiry(instance).await?
            }
            TemporaryPermissionGrantFlowStep::Complete => {
                self.0.handler.handle_complete(instance).await?;
                None // Terminal step
            }
            TemporaryPermissionGrantFlowStep::WorkflowFailed => {
                self.0.handler.handle_workflow_failed(instance).await?;
                None // Terminal step
            }
        };

        // Mark current step as completed
        instance.completed_steps.push(current_step);

        // Move to next step
        match next_step {
            Some(next) => {
                instance.current_step = Some(next);
            }
            None => {
                instance.current_step = None;
                instance.status = FlowStatus::Completed;
            }
        }

        instance.updated_at = chrono::Utc::now();
        Ok(())
    }

    /// Run the flow to completion
    pub async fn run(&self, instance: &mut TemporaryPermissionGrantFlowInstance) -> Result<(), FlowError> {
        while !instance.is_complete() && instance.status != FlowStatus::Waiting {
            self.execute_step(instance).await?;
        }
        Ok(())
    }

    /// Cancel the flow
    pub fn cancel(&self, instance: &mut TemporaryPermissionGrantFlowInstance) { self.0.cancel(instance) }

